SELECT id, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|-----------|-------------|-----------|------------|-----------|\n| Ingestão e backup | Editor | Líder AV | — | Diretor Criativo |\n| Montagem offline | Editor | Líder AV | Diretor AV | — |\n| Revisão de corte | Líder AV | Diretor Criativo | Cliente | Atendimento |\n| Color grading | Colorista | Diretor AV | Editor | — |\n| Mix de áudio | Editor | Líder AV | — | — |\n| Entrega rascunho | Atendimento | Líder AV | — | Comercial |\n| Revisões do cliente | Editor | Líder AV | — | — |\n| Master e exports | Editor | Líder AV | — | Atendimento |', 'step', 2
FROM knowledge_sops WHERE slug = 'tbo-av-009-pos-producao-edicao-color-finalizacao'
